module RefModule(clk, rst, load, data_in, q);

    input clk;
    input rst;
    input load;
    input [3:0] data_in;
    output [3:0] q;
    reg [3:0] q;

      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge rst or posedge dbg_halt)
    begin
        if (rst)
            q <= 4'b0000;
        else if (load)
            q <= data_in;
        else
            q <= {1'b0, q[3:1]};
    end

endmodule
